/// Default weight for n-grams not in the table.
pub const DEFAULT_WEIGHT: f32 = 1.0;

/// Look up the IDF weight for `key` in any sorted `(key, weight)` slice.
///
/// Falls back to [`DEFAULT_WEIGHT`] when `key` is absent from the table.
/// The caller must ensure the slice is sorted ascending by key.
///
/// # AD-355-5 / PF-004
///
/// Key is `u32` (was `u16` before #355 Part B) to match the widened
/// [`crate::ngram::Ngram`] key type.
#[must_use]
#[inline]
pub fn lookup_weight(key: u32, weights: &[(u32, f32)]) -> f32 {
    weights
        .binary_search_by_key(&key, |&(k, _)| k)
        .ok()
        .map(|idx| weights[idx].1)
        .unwrap_or(DEFAULT_WEIGHT)
}

/// Look up the IDF weight of an n-gram by binary search against [`TRIGRAM_WEIGHTS`].
///
/// Returns `None` if the n-gram key is absent from the table.
#[must_use]
pub fn trigram_weight(key: u32) -> Option<f32> {
    TRIGRAM_WEIGHTS
        .binary_search_by_key(&key, |&(k, _)| k)
        .ok()
        .map(|idx| TRIGRAM_WEIGHTS[idx].1)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn table_is_sorted_ascending() {
        let keys: Vec<u32> = TRIGRAM_WEIGHTS.iter().map(|&(k, _)| k).collect();
        let mut sorted = keys.clone();
        sorted.sort();
        assert_eq!(keys, sorted, "TRIGRAM_WEIGHTS must be sorted ascending");
    }

    #[test]
    fn no_duplicate_keys() {
        assert!(
            TRIGRAM_WEIGHTS.windows(2).all(|w| w[0].0 != w[1].0),
            "TRIGRAM_WEIGHTS must not have duplicate keys"
        );
    }

    #[test]
    fn trigram_weight_lookup_works() {
        // If the table is non-empty, the first entry must be findable.
        if let Some(&(key, idf)) = TRIGRAM_WEIGHTS.first() {
            assert_eq!(trigram_weight(key), Some(idf));
        }
    }

    #[test]
    fn default_weight_is_positive() {
        const { assert!(DEFAULT_WEIGHT > 0.0) };
    }

    #[test]
    fn all_idf_values_are_positive() {
        // IDF values must be finite and positive — DEFAULT_WEIGHT fallback applies
        // only when a key is absent, not as a substitute for invalid stored weights.
        assert!(
            TRIGRAM_WEIGHTS
                .iter()
                .all(|&(_, idf)| idf > 0.0 && idf.is_finite())
        );
    }
}
